mapper.sql:
and dt <= #{endDate} and dt >= #{startDate}






    and fans_std >= #{fansRangeLower}



    and fans_std <= #{fansRangeUpper}



    and  first_publish_date >= #{firstPostStartDate}



    and  first_publish_date <= #{firstPostEndDate}



    and  last_publish_date >= #{lastPostStartDate}



    and  last_publish_date <= #{lastPostEndDate}



    and userId in (select userId from url(#{blogIdUrl}, CSV, 'userId UInt64'))



    and blog_url in (select url from url(#{blogHomePageUrl}, CSV, 'url String'))

mapper.select:
select dt,userId as blogId,blog_url,daren_names,blog_name,fans_std,post_count_std,level,domain_r1,is_premium, post_main_content_type,blog_nickname,creator_center_level,create_time,first_publish_date,last_publish_date, premium_post_count,text_post_count_std,photo_post_count_std,video_post_count_std,pay_post_count, receive_hot_std,receive_recommend_cnt,fans_cnt_7d,fans_cnt_30d, formatDateTime(toDateTime(create_time/1000), '%F') as registerDate, multiIf(level = 'S', 'A', level = 'A', 'B', level = 'B', 'C', level = 'C', 'D', level = 'D', 'E', level = 'D*', 'F', 'G') level_sort from lofter.tag_fetch_blog_dd where 1 = 1
order by ${sortField} ${sortOrder}
order by dt desc, level_sort
limit #{limit} offset #{offset}
